struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span() to read header with zero-copy
    if (buffer.size() < sizeof(PacketHeader)) {
        throw std::runtime_error("Buffer too small for packet header");
    }

    // Create a zero-copy view of the header data using Hexi's span
    auto header_span = hexi::span<const PacketHeader>(buffer.data(), sizeof(PacketHeader));

    // Return the header structure by value (small struct, efficient to copy)
    return *header_span.data();
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use view() to read null-terminated string with zero-copy
    const uint8_t* start = buffer.data();
    const uint8_t* current = start;
    const uint8_t* end = start + buffer.size();

    // Find the null terminator
    while (current < end && *current != 0) {
        ++current;
    }

    if (current == end) {
        throw std::runtime_error("Null terminator not found in buffer");
    }

    // Create a zero-copy string view using Hexi's view mechanism
    // Calculate the length of the string (excluding null terminator)
    size_t length = current - start;

    // Return a string_view for zero-copy string access
    return std::string_view(reinterpret_cast<const char*>(start), length);
}
