```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor for the output buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Check if there's enough space for header + items
    // Header: sizeof(uint32_t) = 4 bytes
    // Items: vector size (varint encoded) + each item (uint32_t = 4 bytes each)
    std::size_t required_space = sizeof(uint32_t); // Header space

    // Calculate space needed for items vector
    required_space += hexi::varint_size(items.size()); // Size of vector (varint encoded)
    required_space += items.size() * sizeof(uint32_t); // Each item

    if (adaptor.available() < required_space) {
        return false; // Insufficient space
    }

    // Get write pointer and create binary stream
    auto* write_ptr = adaptor.data();
    hexi::binary_stream stream(write_ptr, adaptor.available());

    // Write header
    stream.write_uint32(header);

    // Write items vector using write_container
    stream.write_container(items);

    // Commit the written data
    adaptor.commit(stream.size());

    return true; // Write successful
}
```

