void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator that manages integers
    block_allocator<int, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Phase 1: Initial allocation pattern
    std::cout << "Phase 1: Initial allocation\n";
    std::cout << "Allocating 3 blocks...\n";

    int* block1 = allocator.allocate();
    int* block2 = allocator.allocate();
    int* block3 = allocator.allocate();

    *block1 = 100;
    *block2 = 200;
    *block3 = 300;

    std::cout << "Block 1: " << block1 << " -> " << *block1 << "\n";
    std::cout << "Block 2: " << block2 << " -> " << *block2 << "\n";
    std::cout << "Block 3: " << block3 << " -> " << *block3 << "\n";

    // Phase 2: Deallocation pattern (simulating push() operations)
    std::cout << "\nPhase 2: Deallocation (push to free list)\n";
    std::cout << "Deallocating block2 first, then block3...\n";

    allocator.deallocate(block2);
    allocator.deallocate(block3);

    // The free list should now have: block3 -> block2 -> nullptr
    // (most recently deallocated becomes the new head)

    // Phase 3: Re-allocation pattern (simulating pop() operations)
    std::cout << "\nPhase 3: Re-allocation (pop from free list)\n";
    std::cout << "Allocating 2 new blocks...\n";

    int* block4 = allocator.allocate();
    int* block5 = allocator.allocate();

    *block4 = 400;
    *block5 = 500;

    std::cout << "Block 4: " << block4 << " -> " << *block4 << "\n";
    std::cout << "Block 5: " << block5 << " -> " << *block5 << "\n";

    // Due to LIFO behavior, block4 should be block3's address
    // and block5 should be block2's address
    std::cout << "\nFree List LIFO Behavior:\n";
    std::cout << "Block 4 should equal Block 3: " << (block4 == block3 ? "YES" : "NO") << "\n";
    std::cout << "Block 5 should equal Block 2: " << (block5 == block2 ? "YES" : "NO") << "\n";

    // Phase 4: Mixed operations
    std::cout << "\nPhase 4: Mixed operations\n";
    std::cout << "Deallocating block1 and block4...\n";

    allocator.deallocate(block1);
    allocator.deallocate(block4);

    // Free list: block4 -> block1 -> block5 -> nullptr
    // (block5 was never deallocated, so it's not in free list)

    std::cout << "Allocating 3 more blocks...\n";

    int* block6 = allocator.allocate();
    int* block7 = allocator.allocate();
    int* block8 = allocator.allocate();

    *block6 = 600;
    *block7 = 700;
    *block8 = 800;

    std::cout << "Block 6: " << block6 << " -> " << *block6 << "\n";
    std::cout << "Block 7: " << block7 << " -> " << *block7 << "\n";
    std::cout << "Block 8: " << block8 << " -> " << *block8 << "\n";

    std::cout << "\nFree List Behavior Confirmation:\n";
    std::cout << "Block 6 should equal Block 4: " << (block6 == block4 ? "YES" : "NO") << "\n";
    std::cout << "Block 7 should equal Block 1: " << (block7 == block1 ? "YES" : "NO") << "\n";
    std::cout << "Block 8 should be a new block: " << (block8 != block1 && block8 != block2 && 
