```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Open the file buffer for reading
    hexi::file_buffer file;
    if (!file.open(file_path.string().c_str(), "rb")) {
        throw std::runtime_error("Failed to open file for reading: " + file_path.string());
    }

    // Get the actual file size to avoid reading beyond EOF
    size_t file_size = file.size();
    size_t bytes_to_read_actual = (bytes_to_read == 0 || bytes_to_read > file_size) ? file_size : bytes_to_read;

    // Read data into vector
    std::vector<uint8_t> buffer(bytes_to_read_actual);
    size_t bytes_read = file.read(buffer.data(), bytes_to_read_actual);

    // Resize buffer to actual bytes read
    if (bytes_read < bytes_to_read_actual) {
        buffer.resize(bytes_read);
    }

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Open the file buffer for reading
    hexi::file_buffer file;
    if (!file.open(file_path.string().c_str(), "rb")) {
        throw std::runtime_error("Failed to open file for preview: " + file_path.string());
    }

    // Get current read position
    size_t current_pos = file.tell();

    // Get the actual file size to avoid reading beyond EOF
    size_t file_size = file.size();
    size_t bytes_to_read_actual = (bytes_to_preview == 0 || bytes_to_preview > file_size) ? file_size : bytes_to_preview;

    // Read data into vector
    std::vector<uint8_t> buffer(bytes_to_read_actual);
    size_t bytes_read = file.read(buffer.data(), bytes_to_read_actual);

    // Resize buffer to actual bytes read
    if (bytes_read < bytes_to_read_actual) {
        buffer.resize(bytes_read);
    }

    // Restore original read position
    file.seek(current_pos, SEEK_SET);

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Open the file buffer for writing (create or truncate)
    hexi::file_buffer file;
    if (!file.open(file_path.string().c_str(), "wb")) {
        throw std::runtime_error("Failed to open file for writing: " + file_path.string());
    }

    // Write data to file
    size_t bytes_written = file.write(data.data(), data.size());

    if (bytes_written != data.size()) {
        throw std::runtime_error("Failed to write all data to file: " + file_path.string());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Open the file buffer for reading
    hexi::file_buffer file;
    if (!file.open(file_path.string().c_str(), "rb")) {
        throw std::runtime_error("Failed to open file for size check: " + file_path.string());
    }

    // Get file size
    return file.size();
}
```

Key features of this implementation:

1. **Error Handling**: Uses proper error checking and throws `std::runtime_error` with descriptive messages when file operations fail.

2. **Bounds Checking**: In `read_file_data` and `preview_file_data`, it checks if the requested bytes exceed the file size and adjusts accordingly.

3. **Position Preservation**: In `preview_file_data`, it saves the current read position before reading and restores it afterward using `seek()`.

4. **Proper File Modes**: Uses "rb" for reading, "wb" for writing (which creates/truncates the file).

5. **Efficient Memory Usage**: Resizes the vector to the actual number of bytes read to avoid unnecessary memory allocation.

6. **Complete Data Writing**: In `write_file_data`, it verifies that all data was successfully written to the file.

The implementation assumes the Hexi library's `file_buffer` class has the following interface:
- `open(filename, mode)`: Opens a file with the specified mode
- `read(buffer, size)`: Reads data into a buffer
- `write(buffer, size)`: Writes data from a buffer
- `seek(position, whence)`: Sets the file position
- `tell()`: Gets the current file position
- `size()`: Gets the file size

