```cpp
#include <hexi/exception.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    try {
        // Re-throw the current exception to catch it
        throw;
    } catch (const hexi::buffer_underrun& e) {
        // Extract information from the buffer_underrun exception
        return UnderrunInfo{
            e.get_read_size(),    // Number of bytes attempted to read
            e.get_total_read(),   // Total bytes read so far
            e.get_buff_size(),    // Total buffer size
            true                  // Exception occurred
        };
    } catch (...) {
        // If it's not a buffer_underrun exception, return default values
        return UnderrunInfo{0, 0, 0, false};
    }
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    try {
        // Attempt to read from the buffer
        buffer.read(destination, length);

        // If successful, return info with occurred=false
        return UnderrunInfo{length, buffer.total_read(), buffer.size(), false};

    } catch (const hexi::buffer_underrun& e) {
        // Catch the buffer_underrun exception and extract information
        return UnderrunInfo{
            e.get_read_size(),    // Number of bytes attempted to read
            e.get_total_read(),   // Total bytes read so far
            e.get_buff_size(),    // Total buffer size
            true                  // Exception occurred
        };
    } catch (...) {
        // Handle any other exceptions
        return UnderrunInfo{length, 0, 0, true};
    }
}
```

